#!/usr/bin/env python3
"""
MKT Christ — Zechariah chapters 1–7 (98 verses, all missing)
Run: python3 scripts/zc-christ-zechariah-1-7-full.py

Key Christological connections:
- 1:8-11 man on red horse among myrtle trees → Rev 6:1-8 (four horsemen); Rev 19:11 (rider on white horse)
- 1:12 angel of YHWH interceding → Heb 7:25; Rom 8:34 (Christ's intercession)
- 2:5 YHWH a wall of fire around Jerusalem → Heb 12:29; Rev 21:23 (God is its light/glory)
- 2:10-11 YHWH comes to dwell among nations → John 1:14 (Word dwelt among us); Rev 21:3
- 3:1-2 Satan accusing Joshua / YHWH rebukes → Rev 12:10; Rom 8:33-34 (who brings charge)
- 3:4 filthy garments removed, festal robes given → Rev 7:14; 2 Cor 5:21 (exchange)
- 3:8 "my servant the Branch" (Tzemach) → John 15:1; Rev 5:5 (root of David)
- 3:9 stone with seven eyes → Rev 5:6 (Lamb with seven horns/eyes)
- 4:6 not by might nor by power but by my Spirit → 1 Cor 2:1-5; Eph 1:19-20
- 4:7 "who are you, O great mountain?" headstone → Matt 21:42; 1 Pet 2:6-7 (cornerstone)
- 4:14 two sons of oil → Rev 11:4 (two witnesses); Heb 1:9 (anointed above companions)
- 5:3 flying scroll / curse → Gal 3:10-13 (Christ redeemed us from the curse)
- 6:12-13 Branch builds temple, priest-king → Heb 7:14-17; Rev 5:9-10 (king and priest)
- 7:9 justice, mercy, compassion → Matt 23:23 (weightier matters of law)
"""

import json
from pathlib import Path

ROOT = Path(__file__).resolve().parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ZECHARIAH = {
    "1": {
        "1": '<p class="christ-theme">The opening date formula — "In the eighth month of the second year of Darius" (520 BCE) — places Zechariah\'s ministry precisely in the post-exilic restoration, alongside Haggai. The prophetic word comes "to Zechariah son of Berekiah son of Iddo" — a priestly genealogy (Neh 12:4,16) that embeds the prophet within the covenant community he addresses. Zechariah means "YHWH has remembered" — a name that summarizes the book\'s central claim: YHWH\'s apparent silence during the exile was not absence but the patience of remembered covenant. Christ is the embodiment of this remembrance: "God so loved the world" is the outworking of YHWH who has "remembered" his covenant (Luke 1:54-55).</p>',
        "2": '<p class="christ-theme">The opening word is direct: "YHWH was very angry (<em>qatsaf</em>) with your ancestors." <em>Qatsaf</em> (wrath/fierce anger) — the covenant wrath arising from persistent rejection of the prophetic call. This anger is not capricious but covenantal: the ancestors turned away, the prophets called, the people did not hear. The same divine anger that drove the exile is what Christ bears on the cross: "God presented Christ as a propitiation through faith in his blood... to demonstrate his righteousness, because in his forbearance he had left the sins committed beforehand unpunished" (Rom 3:25). The <em>qatsaf</em> that drove the exile finds its ultimate resolution in the cross.</p>',
        "3": '<p class="christ-direct">The great covenant-renewal call: "Return to me (<em>shuvah elai</em>), declares YHWH of Hosts, and I will return to you (<em>ve\'ashuv aleikhem</em>), declares YHWH of Hosts." The mutual-return formula — identical to Malachi 3:7 and Zechariah 1:3 — is the covenantal pattern that Christ enacts in his preaching: "Repent, for the kingdom of heaven is at hand" (Matt 4:17). Jesus is the one in whom YHWH returns to his people — "the Word became flesh and dwelt among us" (John 1:14) is the ultimate form of YHWH\'s <em>ve\'ashuv aleikhem</em>. The mutual return is not merely relational movement but the incarnation itself.</p>',
        "4": '<p class="christ-theme">The contrast with the ancestors who "did not hear or pay attention" (<em>lo shamu ve-lo hiqqashvu</em>) defines the failure that Zechariah\'s community must not repeat. The earlier prophets called; the ancestors dismissed the word. What does it mean to hear and attend? Jesus makes hearing the word and doing it the mark of covenant membership: "Everyone then who hears these words of mine and does them will be like a wise man who built his house on the rock" (Matt 7:24). The failure of the ancestors was not ignorance but refusal; Christ calls a community that will hear and build on the rock.</p>',
        "5": '<p class="christ-theme">The rhetorical question — "Where are your ancestors now? And the prophets, do they live forever?" — points to the transience of human existence against the permanence of YHWH\'s word. The ancestors are gone; the prophets are gone; but "my words and my statutes... did they not overtake your ancestors?" — the word outlasted the people it addressed. Christ identifies himself as the eternal Word that was before Abraham (John 8:58) and that will never pass away: "Heaven and earth will pass away, but my words will not pass away" (Matt 24:35). The permanence of YHWH\'s word finds its hypostatic form in Christ.</p>',
        "6": '<p class="christ-theme">The ancestors\' repentance is recorded: "Then they repented and said, \'YHWH of Hosts has done to us what our ways and our practices deserved, just as he determined.\'&#8221; The community accepts covenantal consequence — a rare and significant moment. This is the posture of genuine repentance: acknowledging that what befell them was just. It is the posture Paul describes: "God\'s kindness is meant to lead you to repentance" (Rom 2:4). Christ makes this posture the prerequisite for entering the kingdom: the tax collector who said "God, be merciful to me, a sinner" went home justified (Luke 18:13-14).</p>',
        "7": '<p class="christ-theme">The transition to the night visions (1:7): "On the twenty-fourth day of the eleventh month, which is the month of Shebat, in the second year of Darius, the word of YHWH came to the prophet Zechariah son of Berekiah son of Iddo." The night visions begin here. The precision of the date — the same day Haggai delivered his final oracle — suggests a divine coordination of prophetic word. The night setting of the visions (1:8) points to the darkness-piercing quality of prophetic revelation: Zechariah sees in the night what daylight cannot show. Christ is "the light of the world" who shines in the darkness that cannot comprehend or overcome it (John 1:5; 8:12).</p>',
        "8": '<p class="christ-allusion">The first vision: "In the night I saw a man riding on a red horse! He was standing among the myrtle trees in the valley below, and behind him were red, sorrel, and white horses." The man on the red horse among the myrtles is both the interpreting angel and, in the elaboration of 1:11, the angel of YHWH. Revelation\'s four horsemen (Rev 6:1-8) draw on this imagery — the colored horses sent throughout the earth. More specifically, the rider on the white horse of Revelation 19:11 ("Faithful and True... in righteousness he judges and makes war") fulfills the Zechariah vision: the rider who surveys the earth in patience (1:11: "the earth remains at peace") will return as the warrior who ends the peace of the wicked.</p>',
        "9": '<p class="christ-theme">The prophet\'s question — "What are these, my lord?" — is the posture of the one who does not yet understand what he is seeing. The interpreting angel will show him. This is the epistemological structure of prophetic revelation: the prophet sees but needs the angel\'s interpretation. Christ transforms this structure: "I have much more to say to you, more than you can now bear. But when he, the Spirit of truth, comes, he will guide you into all the truth" (John 16:12-13). The Spirit who interprets Christ\'s work is the fulfillment of the interpreting-angel function in Zechariah\'s vision sequence.</p>',
        "10": '<p class="christ-allusion">The rider explains the colored horses: "They are the ones YHWH has sent to go throughout the earth." The divine surveillance of the entire earth by these angelic scouts anticipates the seven eyes of YHWH "which range throughout the whole earth" (4:10) and the seven spirits of God "sent out into all the earth" (Rev 5:6). The comprehensive divine knowledge of all conditions on earth — through these scouts — is the background against which Christ\'s omniscience operates: "he knew what was in man" (John 2:25) and "I know your works" (Rev 2:2,9,13,19). The one who sends the scouts is the one the scouts report to: Christ enthroned.</p>',
        "11": '<p class="christ-theme">The report of the scouts: "We have gone throughout the earth and found the whole world at rest and in peace." The Pax Persica — the Persian peace — covers the world, but it is a peace that excludes Jerusalem, which still lies in ruins. The irony is sharp: universal peace, but YHWH\'s people unredeemed. This is the world into which Christ is born under the Pax Romana — Caesar Augustus\'s census registration signals the global peace that is simultaneously the moment of the Messiah\'s arrival (Luke 2:1-7). The world is at rest; but the redemption of the covenant people is about to begin.</p>',
        "12": '<p class="christ-allusion">The angel of YHWH intercedes: "How long, O YHWH of Hosts, will you be without compassion for Jerusalem and the cities of Judah, against which you have been angry these seventy years?" The angel of YHWH prays — an act of intercession — for the suffering covenant community. This is the OT form of Christ\'s intercessory priesthood: "he always lives to make intercession for them" (Heb 7:25); "Christ Jesus... who is at the right hand of God and is also interceding for us" (Rom 8:34). The heavenly intercessor of Zechariah 1:12 who asks "how long?" is the prototype of the eternal intercessor who brings the community\'s need before the Father.</p>',
        "13": '<p class="christ-theme">YHWH\'s response to the angel\'s intercession is "gracious and comforting words" (<em>devarim tovim, devarim nechamim</em>). The response is not an answer to the "how long" but a character-declaration: YHWH is gracious and speaks comfort. The great comfort oracle of Isaiah 40:1 — "Comfort, comfort my people" — is the genre that Zechariah\'s vision participates in. Christ fulfills this comfort: "Blessed are those who mourn, for they shall be comforted" (Matt 5:4) — and the Holy Spirit is the <em>Parakletos</em>, the Comforter (John 14:16-17). The comforting word spoken through the angel becomes the comforting Word made flesh.</p>',
        "14": '<p class="christ-theme">The words YHWH spoke to the angel are now proclaimed to the prophet: YHWH is "very jealous for Jerusalem and Zion" (<em>qane&#x2019; liyerushalaim uletziyon qinah gedolah</em>). Divine jealousy (<em>qinah</em>) is covenantal passion — the emotional intensity of exclusive covenant love. This is the same <em>qinah</em> that Paul deploys in describing Christ\'s relationship to the church: "I am jealous for you with a godly jealousy" (2 Cor 11:2). The bridegroom\'s jealousy for his bride — exclusive, passionate, defending — is the character of YHWH\'s love for Jerusalem that Christ will embody in his weeping over the city (Luke 19:41) and his cleansing of its temple (John 2:17, citing Ps 69:9).</p>',
        "15": '<p class="christ-theme">YHWH is "very angry with the nations that are at ease, for I was only a little angry (with Israel) but they intensified the disaster." The nations who were instruments of YHWH\'s discipline overreached — they added to the disaster beyond what YHWH intended. This is the structure that Paul describes in Romans 9-11: the hardening of Israel was partial and purposeful; the nations who were instruments of discipline will themselves face judgment. Christ\'s parable of the wedding banquet makes the same point: those who were invited (Israel) and refused will be replaced by others (Gentiles), but those Gentile others will also face examination (Matt 22:11-14).</p>',
        "16": '<p class="christ-allusion">YHWH\'s return to Jerusalem: "I will return to Jerusalem with compassion (<em>be-rachamim</em>); my house will be built in it... and the measuring line will be stretched over Jerusalem." <em>Rachamim</em> (compassions/mercies) — the deep covenant tenderness of the mother\'s womb (same root as <em>rechem</em>). The divine return to Jerusalem finds its ultimate form in the incarnation: "he came to his own" (John 1:11). The measuring line stretched over Jerusalem anticipates the new Jerusalem measured in Revelation 21:15-17. What Zechariah promises as restored city, Revelation fulfills as the city from heaven — measured, complete, the dwelling of God with humanity.</p>',
        "17": '<p class="christ-theme">The cities of Judah will "overflow with goodness (<em>tov</em>)" and YHWH will "again comfort Zion and again choose Jerusalem." The election-language of <em>bachar</em> (choose) applied to Zion — "YHWH has chosen Zion" (Ps 132:13) — anticipates the new election in Christ. Paul applies the same vocabulary to the church: "Blessed is the God and Father of our Lord Jesus Christ, who has blessed us... just as he chose us in him before the foundation of the world" (Eph 1:3-4). The chosen city becomes the type of the chosen people in Christ — the election of Zion extends to all who are gathered to the one who came from Zion.</p>',
        "18": '<p class="christ-theme">The second vision: "Then I looked up and saw four horns." The four horns (<em>arba\' qeranot</em>) represent the world-powers that scattered Judah, Israel, and Jerusalem. Horns in OT imagery are symbols of power (1 Kgs 22:11; Dan 7:7-8). The four directions of hostile power that dispersed the covenant community anticipate the universal enmity against Christ and his body: "I am sending you out like sheep among wolves" (Matt 10:16). The four horns that scattered are met in the next vision by four craftsmen sent to terrify and cast them down — the eschatological defeat of every power that opposes the covenant people.</p>',
        "19": '<p class="christ-theme">The interpreting angel identifies the horns: "These are the horns that scattered Judah, Israel, and Jerusalem." The comprehensiveness of the scattering — Judah, Israel, Jerusalem — names every dimension of the covenant community\'s dispersal. The reversal announced in subsequent visions is equally comprehensive: the gathering of all the scattered. Jesus uses the same gathering vocabulary: "I will gather my people from the east and from the west" (cf. Isa 43:5-7); "he will send his angels with a loud trumpet call, and they will gather his elect from the four winds, from one end of the heavens to the other" (Matt 24:31).</p>',
        "20": '<p class="christ-theme">Four craftsmen (<em>charashim</em>) appear — skilled workers sent to terrify the horns. "What are these coming to do?" asks the prophet. The answer: "to terrify and throw down the horns of the nations who lifted up their horns against the land of Judah to scatter it." The craftsmen are YHWH\'s agents sent to dismantle what the horns built. In Revelation, the beast\'s power — the horn-power par excellence — is defeated not by superior military force but by the word of the Lamb\'s testimony (Rev 12:11). Christ is the master craftsman (John 1:3, "through him all things were made") who dismantles the works of the enemy through his death and resurrection.</p>',
        "21": '<p class="christ-theme">The second vision closes with the craftsmen designated to terrify the nations\' horns. The economy of the vision is characteristic of Zechariah: threat identified (horns), divine response mobilized (craftsmen), the proportionality of the counter-force to the threat. Paul draws on this logic in describing the armor of God against the spiritual forces of evil (Eph 6:10-18) — each piece of armor matches a specific threat. Christ himself is the divine craftsman whose resurrection life is the definitive counter-force to every power that scatters and destroys: "the reason the Son of God appeared was to destroy the works of the devil" (1 John 3:8).</p>'
    },
    "2": {
        "1": '<p class="christ-allusion">The third vision: "I looked up and saw a man with a measuring line in his hand." The measuring line (<em>chevel middah</em>) is a builder\'s tool — the prophet sees someone about to measure Jerusalem for reconstruction. John\'s Revelation echoes this exactly: a measuring rod given "to measure the temple of God and the altar and those who worship there" (Rev 11:1) and a full city-measurement of the new Jerusalem (Rev 21:15-17). Both the Zechariah vision and Revelation\'s fulfillment use measurement as the sign of divine ownership and planned reconstruction. Christ is the builder of what he measures: "I will build my church" (Matt 16:18).</p>',
        "2": '<p class="christ-allusion">The measurer is going to Jerusalem "to find out its width and its length." The comprehensive measurement anticipates what Revelation 21:16 records: the new Jerusalem measured as 12,000 stadia in each dimension — length, width, and height all equal. The Zechariah vision of the measured city is the OT seed of the Revelation fulfillment. The city whose ruins prompted Zechariah\'s visions becomes the city that needs no measuring tape because its dimensions already embody completeness. Christ is both the measured temple (John 2:19-21, "the temple of his body") and the measurer of the new city.</p>',
        "3": '<p class="christ-theme">The second angel instructs the first to warn the young man: "Run, tell that young man: \'Jerusalem will be inhabited as villages without walls — because of the multitude of people and livestock in it.\'" The overflow of the city beyond any wall — a city too abundant to contain — is the picture of eschatological abundance. Cities needed walls for defense; the city that needs no walls is the city that is fully secure under divine protection (2:5). Revelation\'s new Jerusalem also has no temple because "the Lord God Almighty and the Lamb are its temple" (Rev 21:22) — and its gates are never shut (Rev 21:25). The unwalled city of Zechariah becomes the ungated city of Revelation.</p>',
        "4": '<p class="christ-theme">The promise of measureless population — "Jerusalem will be inhabited as villages without walls, for the multitude of people and livestock" — was fulfilled partially in Nehemiah\'s day but points to the eschatological ingathering. Jesus\'s parable of the great banquet makes the same point: when those first invited refused, the host commands "Go out to the roads and country lanes and compel them to come in, so that my house will be full" (Luke 14:23). The measureless abundance of the restored Jerusalem — beyond any wall — is the eschatological fullness of the community gathered in Christ from every direction.</p>',
        "5": '<p class="christ-allusion">YHWH\'s declaration: "I myself will be a wall of fire (<em>chomotash</em>) around it, and I will be its glory within." <em>Chomotash</em> (wall of fire) — divine protection that exceeds physical fortification. The glory (<em>kavod</em>) within is YHWH\'s own presence. Hebrews 12:29 identifies YHWH as "a consuming fire." Revelation 21:23 announces the fulfillment: "the city has no need of sun or moon to shine on it, for the glory of God gives it light, and its lamp is the Lamb." The glory YHWH promises to be within the city is the glory of the Lamb. The wall of fire is the divine presence that no enemy can penetrate.</p>',
        "6": '<p class="christ-theme">The call to the exiles in Babylon to flee: "Come, come! Flee from the land of the north, declares YHWH." The oracle shifts from vision to direct address — YHWH calls the scattered back. The logic is the same as Revelation 18:4: "Come out of her, my people, so that you do not participate in her sins and receive any of her plagues." Babylon — whether historical (Zechariah\'s context) or eschatological (Revelation\'s context) — is the power-center from which YHWH calls his people. Christ himself is the one who calls: "If anyone hears my voice and opens the door, I will come in" (Rev 3:20) — and the calling is always an exodus.</p>',
        "7": '<p class="christ-theme">"Come, Zion! Escape, you who live in Daughter Babylon!" The call intensifies with the feminine address — Daughter Zion, dwelling in Daughter Babylon, is urged to separate herself from the power that has absorbed her. The tension between Zion-identity and Babylon-captivity is the spiritual tension Paul names for believers: "Do not be conformed to this world, but be transformed by the renewal of your mind" (Rom 12:2). In Christ, the exile is ended — "we have been transferred to the kingdom of his beloved Son" (Col 1:13). The flight from Daughter Babylon is accomplished in conversion to Christ.</p>',
        "8": '<p class="christ-allusion">The declaration that whoever touches YHWH\'s people "touches the apple of his eye (<em>bavat eino</em>)" — the most sensitive and protected part — establishes the intimacy of divine protection over the covenant community. Jesus expresses the same intensity of identification: "Saul, Saul, why are you persecuting me?" (Acts 9:4) — the persecution of the church is the persecution of Christ himself. The one who is the apple of YHWH\'s eye (Israel) and the one who is the eye\'s protector converge in Christ: he is the head of the body that suffers when any part is touched (1 Cor 12:26).</p>',
        "9": '<p class="christ-theme">"For I will surely shake my hand against them, and they will be plunder for their own servants. Then you will know that YHWH of Hosts has sent me." The shaking hand of judgment against Babylon anticipates Revelation\'s judgment oracles against the great city: "fallen, fallen is Babylon the great" (Rev 18:2). The self-referential "you will know that YHWH of Hosts has sent me" is the divine messenger formula — the one speaking is simultaneously YHWH\'s agent and identified with YHWH (2:8-9,11 — a subtle Trinitarian anticipation). Christ embodies this identity: "Whoever has seen me has seen the Father" (John 14:9).</p>',
        "10": '<p class="christ-direct">&#x201C;Shout for joy and be glad, O Daughter Zion! For look, I am coming and I will dwell in your midst (<em>shakhanti betokekh</em>), declares YHWH.&#x201D; <em>Shakhanti betokekh</em> — I will tabernacle/dwell in your midst. John 1:14: &#x201C;The Word became flesh and tabernacled (<em>eskēnōsen</em>) among us.&#x201D; The verbal connection is exact: <em>shakan</em> (Hebrew) → <em>skēnoō</em> (Greek LXX) → John\'s <em>eskēnōsen</em>. The incarnation is the fulfillment of Zechariah 2:10. YHWH\'s promised dwelling in the midst of his people is the Word taking on flesh. The Daughter Zion who is called to shout for joy at YHWH\'s coming finds her joy in the one who comes as a human being.</p>',
        "11": '<p class="christ-allusion">&#x201C;Many nations will join themselves to YHWH on that day, and they will be my people, and I will dwell in your midst.&#x201D; The joining of the nations to YHWH — becoming <em>lam le\'am</em> (my people) — is the eschatological universalization of the covenant. Paul\'s central argument in Ephesians is this: &#x201C;This mystery is that the Gentiles are fellow heirs, members of the same body, and partakers of the promise in Christ Jesus through the gospel&#x201D; (Eph 3:6). The nations who join themselves to YHWH in Zechariah 2:11 join through Christ in Paul\'s framework. Revelation 21:3 records the fulfillment: &#x201C;They will be his peoples (<em>laoi</em>, plural), and God himself will be with them.&#x201D;</p>',
        "12": '<p class="christ-theme">YHWH will "inherit Judah as his portion in the holy land and will again choose Jerusalem." The <em>nachalah</em> (inheritance) language reverses: instead of Israel inheriting the land from YHWH, YHWH inherits Judah as his portion. The mutual-possession structure is fully realized in Christ: "heirs of God and fellow heirs with Christ" (Rom 8:17); Christ is the heir of all things (Heb 1:2) and the church is "a people for his own possession" (1 Pet 2:9). The one who chooses Jerusalem is the one who wept over it (Luke 19:41) — the divine election of the city expressed through the tears of the incarnate Lord.</p>',
        "13": '<p class="christ-theme">&#x201C;Be silent, all flesh, before YHWH, for he has roused himself from his holy dwelling.&#x201D; The call to cosmic silence before YHWH\'s awakening echoes Malachi 2:20\'s &#x201C;let all the earth keep silence before him.&#x201D; Habakkuk 2:20 uses the identical formula. Revelation 8:1 enacts this: &#x201C;there was silence in heaven for about half an hour&#x201D; before the judgments proceed. The silence of all flesh before YHWH\'s stirring is the creaturely recognition of the Creator\'s initiative. Christ is the one in whom YHWH has &#x201C;roused himself&#x201D; — the incarnation is the divine awakening into human history.</p>',
    },
    "3": {
        "1": '<p class="christ-allusion">The fourth vision: Joshua the high priest standing before the angel of YHWH, with Satan (<em>ha-satan</em>) standing at his right hand to accuse him. The heavenly courtroom — accuser, defender, judge — is the scene. Revelation 12:10 declares the resolution of this exact scene: &#x201C;the accuser of our brothers has been thrown down, who accuses them day and night before our God.&#x201D; Romans 8:33-34 asks the same question from the opposite side: &#x201C;Who shall bring any charge against God\'s elect? It is God who justifies. Who is to condemn? Christ Jesus is the one who died — more than that, who was raised — who is at the right hand of God, who indeed is interceding for us.&#x201D; The heavenly accusation that confronts Joshua finds its eternal answer in Christ\'s intercession.</p>',
        "2": '<p class="christ-direct">YHWH\'s rebuke of Satan: &#x201C;The LORD rebuke you, Satan! The LORD who has chosen Jerusalem rebuke you! Is not this man a burning stick snatched from the fire?&#x201D; Jude 9 quotes this rebuke-formula in the dispute over Moses\'s body — &#x201C;even the archangel Michael, contending with the devil, did not presume to pronounce a blasphemous judgment, but said, \'The Lord rebuke you.\'&#x201D; The formula is identical; its force is YHWH\'s own authority silencing the accuser. The Joshua who stands as a &#x201C;burning stick snatched from the fire&#x201D; is the type of every believer rescued from judgment: saved &#x201C;as though through fire&#x201D; (1 Cor 3:15). Christ is the one who does the snatching.</p>',
        "3": '<p class="christ-type">Joshua is dressed in filthy garments (<em>begadim tsoim</em>) — the OT term for garments rendered ritually impure, often associated with bodily defilement. For a high priest standing before YHWH to be in filthy garments is a catastrophic problem: the high priest\'s vestments were sacred, specific, and carefully maintained. The filthy garments are the visual representation of the covenant community\'s sin. Paul\'s declaration is the theological resolution: &#x201C;For our sake he made him to be sin who knew no sin, so that in him we might become the righteousness of God&#x201D; (2 Cor 5:21). Christ takes the filth; those in him receive the clean garment.</p>',
        "4": '<p class="christ-type">The command from the angel: &#x201C;Remove the filthy garments from him.&#x201D; Then: &#x201C;See, I have taken your guilt away from you, and I will clothe you with rich robes (<em>machalatsot</em>).&#x201D; The exchange is explicit — filthy garments removed, festal robes given — and the verbal declaration accompanies the physical sign: &#x201C;I have taken away your guilt (<em>iniquity</em>).&#x201D; Revelation 7:14 describes the great multitude in white robes: &#x201C;They have washed their robes and made them white in the blood of the Lamb.&#x201D; The blood of the Lamb is what makes filthy garments white — what the angel announces symbolically in Zechariah, the cross enacts historically. The exchange of garments is the gospel.</p>',
        "5": '<p class="christ-theme">Zechariah speaks up: &#x201C;Let them put a clean turban (<em>tsanif</em> — the high priest\'s head-wrapping) on his head.&#x201D; The angel of YHWH completes the reclothing. The full vestment of the high priest is restored — the filthy garments replaced with the complete priestly regalia. Hebrews 4:14-16 presents Christ as the fulfillment of this priestly restoration: &#x201C;since we have a great high priest who has passed through the heavens, Jesus the Son of God... let us then with confidence draw near to the throne of grace.&#x201D; The Joshua whose priestly vestments are restored by divine action points to the great High Priest who is clothed in permanent righteousness and carries his people into the divine presence.</p>',
        "6": '<p class="christ-theme">The angel of YHWH charges Joshua: the conditions and promises of a renewed priestly covenant. &#x201C;The angel of YHWH solemnly assured Joshua.&#x201D; The solemnity of the charge — with the verb <em>ya\'ad</em> (to charge/commission) — marks this as a covenant-renewal moment. The priestly office is being reconstituted after the exile\'s defilement. The charge that follows (&#x201C;if you walk in my ways and keep my requirements&#x201D;) is the conditional covenant formula applied to the priestly calling. Christ is the high priest who perfectly keeps every condition of the divine charge — his perfect obedience is the basis on which his intercession is effective (Heb 7:26-28).</p>',
        "7": '<p class="christ-theme">The promise to Joshua: &#x201C;if you walk in my ways and keep my requirements, then you will govern my house and have charge of my courts, and I will give you a place among those standing here.&#x201D; The priestly access to YHWH\'s house — standing before him with the angelic company — is the conditional promise given to a faithful high priest. Christ makes this access unconditional for all who are in him: &#x201C;you have come to... the heavenly Jerusalem... to the assembly of the firstborn who are enrolled in heaven... and to Jesus, the mediator of a new covenant&#x201D; (Heb 12:22-24). The standing-before-YHWH that Joshua receives conditionally, believers receive through Christ\'s mediation.</p>',
        "8": '<p class="christ-direct">&#x201C;Hear now, O Joshua the high priest, you and your colleagues who sit before you — for these men are a sign (or: a wonder, <em>mofet</em>), for behold, I will bring my servant the Branch (<em>et-avdi Tzemach</em>).&#x201D; <em>Tzemach</em> (Branch/Sprout) — the Messianic title from Isaiah 4:2, Jeremiah 23:5, and 33:15. &#x201C;My servant&#x201D; is the Isaianic Servant vocabulary (Isa 42:1; 52:13). John 15:1-5: &#x201C;I am the true vine&#x201D; — Jesus takes up the branch/vine imagery. Revelation 5:5: &#x201C;the Lion of the tribe of Judah, the Root of David&#x201D; — the root from which the branch grows. The Branch announced to Joshua is Christ, who is simultaneously the servant and the royal shoot from the Davidic root.</p>',
        "9": '<p class="christ-allusion">&#x201C;For behold, on the stone that I have set before Joshua — on one stone with seven eyes — I will engrave its inscription, declares YHWH of Hosts.&#x201D; The stone with seven eyes — a single stone bearing seven faces of divine omniscience — is the OT image that Revelation 5:6 develops: &#x201C;a Lamb standing, as though it had been slain, with seven horns and with seven eyes, which are the seven spirits of God sent out into all the earth.&#x201D; The seven eyes of Zechariah\'s stone are the seven eyes of the Lamb — the complete knowledge of the one who searches all things. The engraved stone (a foundation stone?) is the cornerstone Christ becomes: &#x201C;the stone the builders rejected has become the cornerstone&#x201D; (Ps 118:22; 1 Pet 2:6-7).</p>',
        "10": '<p class="christ-theme">The oracle closes with the eschatological promise: &#x201C;On that day, each of you will invite your neighbor to sit under your vine and fig tree, declares YHWH of Hosts.&#x201D; The vine-and-fig-tree imagery (= shalom, Solomonic peace, Mic 4:4; 1 Kgs 4:25) is the picture of the messianic age in its fullness. Jesus standing beneath the fig tree sees Nathanael (John 1:48) — a compressed sign of the age that has arrived. The invitation to sit under vine and fig tree — to enter the Messianic peace — is what Christ issues to all: &#x201C;Come to me, all who labor and are heavy laden, and I will give you rest&#x201D; (Matt 11:28). The sitting-under-the-vine is the rest Christ provides.</p>',
    },
    "4": {
        "1": '<p class="christ-theme">The fifth vision begins with the angel waking the prophet &#x201C;like someone roused from sleep.&#x201D; The sleep/wakefulness motif — the prophetic consciousness entering and exiting the visionary state — has Christological resonance: Paul uses the same image for the eschatological awakening of believers: &#x201C;Awake, O sleeper, and arise from the dead, and Christ will shine on you&#x201D; (Eph 5:14). The angel waking Zechariah is the prototype of Christ waking the spiritually sleeping — rousing them from the torpor of sin into the clarity of divine vision.</p>',
        "2": '<p class="christ-allusion">The vision: &#x201C;a solid gold lampstand with a bowl at the top and seven lamps on it, with seven channels to the lamps — and two olive trees beside it, one on the right of the bowl and one on the left.&#x201D; Revelation 1:12-20 develops this image: seven golden lampstands in which Christ walks, representing the seven churches. Christ is both the one who tends the lampstands and the light that shines through them. The golden lampstand of Zechariah 4:2 is the OT prototype for the church as light-bearer — not the source of light but the vessel through which divine light is expressed to the world (Matt 5:14-16).</p>',
        "3": '<p class="christ-allusion">The two olive trees flanking the lampstand — &#x201C;one on the right of the bowl and one on the left&#x201D; — are identified in 4:14 as &#x201C;the two sons of oil.&#x201D; Revelation 11:4 identifies the two witnesses as &#x201C;the two olive trees and the two lampstands that stand before the Lord of the earth.&#x201D; The anointing function of the olive trees — continuously supplying oil to the lampstand — is the function of the Spirit who anoints Christ (&#x201C;Christ&#x201D; = the Anointed One) and through him the church. Hebrews 1:9 applies Psalm 45:7 to Christ: &#x201C;God, your God, has anointed you with the oil of gladness beyond your companions.&#x201D;</p>',
        "4": '<p class="christ-theme">&#x201C;I asked the angel who was speaking with me, \'What are these, my lord?\' &#x201D; The prophet\'s repeated question — seeking understanding of the vision — models the posture of prayer: bring the question honestly before the divine interpreter. Jesus promises the same interpretive access through the Spirit: &#x201C;He will teach you all things and remind you of everything I have said to you&#x201D; (John 14:26). The prophet who asks &#x201C;what are these?&#x201D; and receives angelic explanation is the OT template for the believer who asks and receives understanding through Christ\'s Spirit.</p>',
        "5": '<p class="christ-theme">The angel responds with his own question: &#x201C;Don\'t you know what these are?&#x201D; The question is rhetorical — the angel is about to explain. But the rhetorical question itself models the patience of the divine teacher who does not simply deliver information but draws the student into recognition. Jesus consistently teaches this way: &#x201C;Who do the crowds say I am?... But who do you say I am?&#x201D; (Luke 9:18-20). The teacher who responds to a question with a question is inviting deeper engagement than mere information-transfer.</p>',
        "6": '<p class="christ-direct">The great oracle: &#x201C;Not by might, nor by power, but by my Spirit, says YHWH of Hosts.&#x201D; <em>Lo be-chayil ve-lo ve-khoach ki im be-ruachi</em>. The rebuilding of the temple will not happen through human resources or military force but through the Spirit alone. Paul applies this principle to the cross and the gospel: &#x201C;For the word of the cross is foolishness to those who are perishing, but to us who are being saved it is the power of God&#x201D; (1 Cor 1:18). The kingdom does not come through might or power — it comes through the Spirit who raised Jesus from the dead (Eph 1:19-20). The Spirit by whom the temple is rebuilt is the Spirit who raised Christ.</p>',
        "7": '<p class="christ-allusion">&#x201C;What are you, O great mountain? Before Zerubbabel you shall become a plain! And he shall bring forward the top stone, the capstone (<em>rosh ha-even</em>) amid shouts of \'Grace, grace to it!\'&#x201D; The mountain-become-plain before the divine servant anticipates Jesus\'s teaching: &#x201C;Truly, I say to you, if you have faith like a grain of mustard seed, you will say to this mountain, \'Move from here to there,\' and it will move&#x201D; (Matt 17:20; Mark 11:23). The obstacle-dissolving power of divine commission is what Christ makes available to faith. The capstone brought forward amid &#x201C;grace, grace&#x201D; is the rejected stone that becomes the cornerstone (Ps 118:22), applied to Christ in Matt 21:42 and 1 Pet 2:6-7.</p>',
        "8": '<p class="christ-theme">A new oracle comes to Zechariah directly — not through the angel of the vision. &#x201C;Moreover, the word of YHWH came to me saying...&#x201D; The shift from visionary to direct word marks the importance of what follows (4:9-10). The layering of prophetic modes — vision, angelic interpretation, direct word — models the comprehensive character of divine revelation. John 1:1-14 establishes Christ as the ultimate prophetic mode: the Word itself becoming flesh rather than being delivered through messengers, visions, or angelic interpreters.</p>',
        "9": '<p class="christ-allusion">&#x201C;The hands of Zerubbabel have laid the foundation of this house; his hands will also complete it (<em>yevatzune&#x02BC;ahu</em>). Then you will know that YHWH of Hosts has sent me to you.&#x201D; The same hands that begin will finish — divine assurance that the work of reconstruction will reach completion. Philippians 1:6 applies this assurance directly to Christ\'s work: &#x201C;I am sure of this, that he who began a good work in you will bring it to completion at the day of Jesus Christ.&#x201D; The one whose hands laid the foundation of the new temple in Zechariah is the type of the one who will complete what he started in his people.</p>',
        "10": '<p class="christ-allusion">&#x201C;For whoever has despised the day of small things shall rejoice, and shall see the plumb line (<em>even ha-bedil</em>) in the hand of Zerubbabel. These seven are the eyes of YHWH, which range throughout the whole earth.&#x201D; The seven eyes of YHWH — here sent throughout the earth — are identified with the stone in the vision. Revelation 5:6 embeds these seven eyes in the Lamb: the Lamb slain has seven eyes which are &#x201C;the seven spirits of God sent out into all the earth.&#x201D; The omniscient divine gaze (seven eyes ranging the earth) is located in Christ. The &#x201C;day of small things&#x201D; despised by some is the mustard-seed beginning that Christ celebrates: the kingdom of heaven is like a mustard seed — the smallest of seeds becoming the largest of plants (Matt 13:31-32).</p>',
        "11": '<p class="christ-theme">The prophet presses the question again: &#x201C;What are these two olive trees?&#x201D; The persistence of the question models the spiritual posture of &#x201C;ask and it will be given to you; seek and you will find; knock and the door will be opened to you&#x201D; (Matt 7:7-8). The one who keeps asking receives the answer. Christ\'s promise is an elaboration of the angel\'s patient response to Zechariah\'s repeated questioning: the divine interpreter does not tire of the earnest question.</p>',
        "12": '<p class="christ-theme">Zechariah asks again — more precisely this time: &#x201C;What are these two branches of the olive trees that are beside the two golden pipes from which the golden oil is poured?&#x201D; The golden oil (<em>zahav</em>) flowing through golden pipes: pure anointing oil without human mediation, directly from the olive trees to the bowl that feeds the lamps. The unmediated flow of the Spirit through Christ — &#x201C;God has given the Spirit without measure&#x201D; (John 3:34) — is the NT fulfillment of this pipeline image. Christ is both the source and the conductor of the Spirit\'s supply to his people.</p>',
        "13": '<p class="christ-theme">The angel responds with his own question: &#x201C;Do you not know what these are?&#x201D; And Zechariah admits: &#x201C;No, my lord.&#x201D; The intellectual humility of &#x201C;I do not know&#x201D; before the divine interpreter is the prerequisite for genuine understanding. Jesus singles out those who know they do not know: &#x201C;Unless you turn and become like children, you will never enter the kingdom of heaven&#x201D; (Matt 18:3). The childlike &#x201C;no, my lord&#x201D; that Zechariah offers is the model posture — honesty about ignorance that opens the way for the angel\'s revelation.</p>',
        "14": '<p class="christ-allusion">The answer: &#x201C;These are the two sons of oil (<em>benei ha-yitshar</em>) who stand before the Lord of the whole earth.&#x201D; The sons of oil are Zerubbabel (royal/Davidic) and Joshua (priestly) — the two leadership figures of the restoration who are continuously anointed by the Spirit to enable the community\'s flourishing. Christ combines both offices permanently: &#x201C;You are a priest forever, after the order of Melchizedek&#x201D; (Heb 7:17) — the royal-priestly figure. Revelation 11:4 identifies the two witnesses as &#x201C;the two olive trees and the two lampstands.&#x201D; The dual anointing of Zerubbabel and Joshua is reunified in Christ the King-Priest.</p>',
    },
    "5": {
        "1": '<p class="christ-allusion">The sixth vision: a flying scroll (<em>megillah mefah</em>). &#x201C;I looked up again and saw a scroll flying through the air.&#x201D; The flying scroll — a massive written document moving through space — has several NT parallels. Most directly, Revelation 5:1 describes the scroll with seven seals held in the right hand of the one on the throne. Revelation 10:2 describes a small scroll in the angel\'s hand. The scroll in Zechariah is the instrument of the covenant curse; the scroll in Revelation contains the judgments that accompany redemption. Both uses of the flying/opened scroll point to the written word as the agent of divine action in the world.</p>',
        "2": '<p class="christ-theme">The dimensions of the scroll: twenty cubits long and ten cubits wide. These are the exact dimensions of the porch of Solomon\'s temple (1 Kgs 6:3) — a connection that links the curse-scroll to the covenant structure of the temple. The scroll\'s size is architectural-covenantal. The covenant curses that the scroll carries are not arbitrary but precisely matched to the covenant structure of YHWH\'s house. Christ who is the temple (John 2:21) embodies the covenant in which these curses operate — and in whom they are resolved: &#x201C;Christ redeemed us from the curse of the law by becoming a curse for us&#x201D; (Gal 3:13).</p>',
        "3": '<p class="christ-allusion">&#x201C;This is the curse that goes out over the whole land. According to one side of it, every thief will be expelled; according to the other side, everyone who swears falsely will be expelled.&#x201D; The two sides of the scroll carry two categories of covenant violation: theft and false oaths — the two forms of covenantal violation that destroy community trust. Galatians 3:10 describes the scroll\'s function in theological terms: &#x201C;All who rely on works of the law are under a curse, for it is written, \'Cursed be everyone who does not abide by all things written in the Book of the Law, and do them.\'&#x201D; The curse-scroll that expels violators is what Christ endures on the cross so that its expulsion falls on him rather than on those who believe.</p>',
        "4": '<p class="christ-type">&#x201C;I will send it out, declares YHWH of Hosts, and it will enter the house of the thief and the house of the one who swears falsely by my name. It will remain in that house and consume it, both its timbers and its stones.&#x201D; The curse that consumes the house of the covenant violator — penetrating timber and stone — is the covenant consequence entering the very structure of a life built on theft and falsehood. Hebrews 4:12-13 describes the word of God similarly: &#x201C;piercing to the division of soul and of spirit... discerning the thoughts and intentions of the heart.&#x201D; Christ absorbs the consuming curse so that those in him are not consumed: &#x201C;There is therefore now no condemnation for those who are in Christ Jesus&#x201D; (Rom 8:1).</p>',
        "5": '<p class="christ-theme">The seventh vision begins: &#x201C;Then the angel who was speaking with me came forward and said to me, \'Look up and see what this is that is appearing.\'&#x201D; The invitation to &#x201C;look up and see&#x201D; is the characteristic prophetic posture — the upward orientation that receives divine revelation. Hebrews 12:2 names this posture as the defining characteristic of Christian faith: &#x201C;fixing our eyes on Jesus, the founder and perfecter of our faith.&#x221D; The looking-up-to-see that Zechariah practices through the night visions is the posture that every believer is called to maintain toward Christ.</p>',
        "6": '<p class="christ-theme">The angel asks, &#x201C;What is it?&#x221D; — and answers: &#x201C;This is the measuring basket (ephah) that is going out.&#x221D; And: &#x201C;This is their iniquity in all the land.&#x221D; The ephah (a standard dry measure) becomes the container for the concentrated iniquity of the land. The commercial measuring unit becomes the vehicle of covenant violation — in Amos 8:5, corrupt merchants use the ephah dishonestly. Christ names the same iniquity-concentration when he says the Pharisees &#x201C;fill up the measure of your fathers&#x221D; (Matt 23:32) — iniquity accumulating to its full measure before judgment comes.</p>',
        "7": '<p class="christ-theme">&#x201C;Then a lead cover was raised, and there was a woman sitting in the basket!&#x221D; The woman represents the personified iniquity — wicked commerce, perhaps — that is being contained and removed. The lead cover (&#x201C;the heaviness,&#x221D; <em>kikar oferet</em>) seals the iniquity for transport. The containment of evil for removal is the structure of the eschatological quarantine that Revelation describes: the beast, the false prophet, and Satan all consigned to the lake of fire (Rev 20:10). Evil is not merely described but definitively removed — contained, transported, and deposited away from the restored community.</p>',
        "8": '<p class="christ-type">&#x201C;This is Wickedness (<em>Risha</em>),&#x221D; he said. And he pushed her back into the basket and slammed the lead cover over its opening.&#x221D; The personification of wickedness as a woman thrust back into the container and sealed — forcibly confined — is the vision of divine authority over evil. Christ\'s authority over unclean spirits in the Gospels enacts this containment: &#x201C;He commanded the unclean spirit, saying to it, \'Be silent, and come out of him!&#x221D; (Mark 1:25). The authority that seals wickedness in the ephah is the same authority that Christ exercises over every manifestation of evil encountered in his ministry.</p>',
        "9": '<p class="christ-allusion">Two women with wings like stork-wings carry the basket between earth and sky to remove it. Angels as agents of divine containment and removal operate throughout Revelation — gathering the harvest, binding the beast, confining Satan (Rev 20:1-3). The wind under the women\'s wings anticipates the wind-borne activity of the Spirit carrying out divine judgment. The stork was an unclean bird in Leviticus 11:19 — perhaps an intentional irony: unclean agents removing uncleanness. God uses imperfect instruments for perfect purposes, as Paul notes: &#x201C;God chose what is foolish in the world to shame the wise&#x221D; (1 Cor 1:27).</p>',
        "10": '<p class="christ-theme">The prophet asks, &#x201C;Where are they carrying the basket?&#x221D; The answer: to the land of Shinar — ancient Babylon — to build it a house and set it on its base. Evil is removed from the land of Israel and repatriated to Babylon, its origin point. Revelation 17-18 spells out Babylon\'s final judgment — the city of wickedness built and then burned. The iniquity removed from the covenant land in Zechariah\'s vision is the iniquity that accumulates in Babylon until its final judgment. Christ\'s cross is the definitive removal: the sin carried away &#x201C;as far as the east is from the west&#x221D; (Ps 103:12).</p>',
        "11": '<p class="christ-theme">&#x201C;To build a house for it in the land of Shinar. When it is ready, the basket will be set there in its place.&#x221D; Wickedness gets its permanent installation in Babylon — contained, exported, and settled in the place of human rebellion (Babylon = Babel = Gen 11). The contrast with YHWH\'s house being built in Jerusalem (4:9; 6:12-13) is complete: YHWH\'s house in Zion, wickedness housed in Babylon. The two building projects — YHWH\'s temple and Babylon\'s wickedness-shrine — run in parallel until Revelation\'s final judgment removes Babylon forever (Rev 18:21) and establishes the new Jerusalem permanently (Rev 21:2).</p>',
    },
    "6": {
        "1": '<p class="christ-allusion">The eighth and final vision: four chariots coming out from between two bronze mountains. The four chariots echo the four horsemen of Revelation 6:1-8 — the colored horses sent throughout the earth. &#x201C;The four winds of heaven going out after presenting themselves before the Lord of all the earth&#x221D; (6:5) are angelic powers operating under divine commission. Revelation 19:11 presents Christ himself as the rider on the white horse who judges and makes war — the culmination of all the horsemen-visions, both Zechariah\'s and Revelation\'s. The chariot-visions frame the entire vision sequence and point to the ultimate cavalry commander.</p>',
        "2": '<p class="christ-theme">Red, black, white, and dappled horses — four colored teams of horses pulling four chariots. The colors evoke power, death, victory, and mixed forces. Revelation\'s four horsemen (Rev 6:2-8) use white, red, black, and pale — a near-parallel sequence. The divine deployment of angelic cavalry throughout the earth is the visual assertion of YHWH\'s sovereign oversight of all earthly affairs. Christ is the one who holds the seven stars and walks among the lampstands (Rev 1:16-20) — the comprehensive sovereignty expressed through the chariot-vision finds its incarnate form in the one who exercises authority over all creation (Matt 28:18).</p>',
        "3": '<p class="christ-theme">The dappled horses are described as particularly strong (&#x201C;powerful animals&#x221D;). The divine army deployed across the earth carries mixed forces for mixed conditions — the flexibility of divine action matched to every situation. Paul\'s theology of divine sufficiency works the same way: &#x201C;Not that I am speaking of being in need, for I have learned, in whatever situation I am, to be content... I can do all things through him who strengthens me&#x221D; (Phil 4:11,13). Christ\'s sufficiency adapts to every situation his people face — like the dappled team suited for varied terrain.</p>',
        "4": '<p class="christ-theme">&#x201C;Then I asked the angel who was speaking with me, \'What are these, my lord?\'&#x221D; The prophet\'s consistent posture of asking — seeking interpretation rather than presuming understanding — is the model of spiritual wisdom. James describes this as the basic posture of the believer: &#x201C;If any of you lacks wisdom, let him ask God, who gives generously to all without reproach, and it will be given him&#x221D; (Jas 1:5). Christ promises the same: &#x201C;Ask and it will be given to you&#x221D; (Matt 7:7). The prophet who asks the angel models the disciple who asks the Lord.</p>',
        "5": '<p class="christ-allusion">The angel identifies the chariots: &#x201C;These are the four winds of heaven going out after presenting themselves before the Lord of all the earth.&#x221D; <em>Arba\' ruchot ha-shamayim</em> (the four winds/spirits of heaven) — the same four winds that scatter and gather in Jesus\'s eschatological discourse: &#x201C;He will send his angels with a loud trumpet call, and they will gather his elect from the four winds, from one end of the heavens to the other&#x221D; (Matt 24:31). The four winds that go out after presenting before YHWH are the same four winds from which Christ\'s elect are gathered at the end. The beginning of Zechariah\'s dispatch becomes the conclusion of Christ\'s gathering.</p>',
        "6": '<p class="christ-theme">The specific assignments: the black horses go north, the white horses go after them, the dappled ones go south. The north and south are the primary axes of international pressure on Israel — Babylon from the north, Egypt from the south. The divine deployment of angelic cavalry to these specific directions asserts comprehensive sovereignty. Christ\'s final commission has the same universal scope: &#x201C;Go and make disciples of all nations&#x221D; (Matt 28:19) — every direction, every power, every domain is included in the commission that the risen Lord gives to his followers.</p>',
        "7": '<p class="christ-theme">The powerful horses go throughout the earth, eager to patrol it. &#x201C;He said, \'Go, patrol throughout the earth!\' and they patrolled throughout the earth.&#x221D; The divine command and immediate obedience — no delay between the word and the action — models the absolute responsiveness of divine messengers to YHWH\'s will. Hebrews 1:14 describes the angels as &#x201C;ministering spirits sent out to serve for the sake of those who are to inherit salvation.&#x221D; The patrol horses of Zechariah 6:7 are the ancestors of the ministering spirits of Hebrews 1:14 — divine agents dispatched in service of the covenant community.</p>',
        "8": '<p class="christ-theme">&#x201C;Then he called to me, \'Look, those going toward the north country have caused my Spirit to rest in the north country.\'&#x221D; <em>Henichu et-ruachi</em> — &#x201C;they have caused my Spirit to rest/be satisfied.&#x221D; The patrol to the north country achieves the result of YHWH\'s Spirit finding rest — the satisfaction of divine purpose accomplished. This is the language of the servant\'s mission in Isaiah 42:1 (&#x201C;in whom my soul delights&#x221D;, lit. &#x201C;who is pleasing to me&#x221D;) and of God resting in Sabbath completion (Gen 2:2-3). Christ\'s accomplished work is described in the same terms: &#x201C;when Christ had offered for all time a single sacrifice for sins, he sat down at the right hand of God&#x221D; (Heb 10:12) — the rest of completed work.</p>',
        "9": '<p class="christ-theme">A direct oracle comes to Zechariah: &#x201C;The word of YHWH came to me.&#x221D; The night visions are over; now a concrete symbolic action follows. The shift from visionary to enacted-sign is characteristic of prophetic communication — the body as well as the mind becomes the vehicle of divine message. Christ\'s ministry similarly moves between word and deed: teaching and healing, parable and miracle, the word proclaimed and the word enacted in signs. The prophet\'s embodied response to divine word anticipates the one in whom word and deed are permanently unified.</p>',
        "10": '<p class="christ-theme">Zechariah is to take silver and gold from the exilic community — Heldai, Tobijah, and Jedaiah who have come from Babylon — and go to the house of Josiah son of Zephaniah. The bringing of wealth from the nations (Babylon) into Jerusalem for the construction of the crown is a small enacted version of Isaiah\'s vision: &#x201C;the wealth of the nations shall come to you&#x221D; (Isa 60:5). Revelation 21:26 describes the fulfillment: &#x201C;The glory and the honor of the nations will be brought into&#x221D; the new Jerusalem. The silver and gold brought from Babylon anticipate the nations bringing their glory to Christ.</p>',
        "11": '<p class="christ-direct">&#x201C;Take the silver and gold and make a crown (<em>atarot</em>) and set it on the head of Joshua son of Jehozadak, the high priest.&#x221D; A crown on the high priest — not the governor Zerubbabel (the expected royal figure) but Joshua. The fusion of royal crown with priestly office on a single person is the enacted prophecy of the Branch (6:12-13) who will be both king and priest. Hebrews 7:14-17 identifies Christ as the fulfillment: &#x201C;it is evident that our Lord was descended from Judah... he has become a priest, not on the basis of a legal requirement... but by the power of an indestructible life.&#x221D; The crowned priest of Zechariah 6:11 is the type of Christ, the eternal priest-king.</p>',
        "12": '<p class="christ-direct">&#x201C;Say to him, &#x2018;Thus says YHWH of Hosts: Behold, the man whose name is the Branch (<em>Tzemach</em>): for he shall branch out from his place, and he shall build the temple of YHWH.&#x201D; The Branch announced here is both the builder of the temple and a royal figure who &#x201C;branches out from his place&#x221D; — a botanical image for natural, organic growth from a root. Jeremiah 23:5 and 33:15 identify the Branch as the Davidic king who will reign wisely. Jesus is the fulfillment: the one who builds the temple of his body (John 2:19-21) and builds the church (Matt 16:18). The Branch that grows from David\'s root grows into the vine in whom all branches must abide (John 15:1-5).</p>',
        "13": '<p class="christ-direct">&#x201C;It is he who shall build the temple of YHWH and shall bear royal honor, and shall sit and rule on his throne. And there shall be a priest on his throne, and the counsel of peace shall be between them both.&#x221D; The unique figure who is simultaneously king on the throne and priest on the throne — with peace between the two offices — is the priest-king of Psalm 110:1-4 that Hebrews quotes repeatedly. &#x201C;You are a priest forever, after the order of Melchizedek&#x221D; (Heb 7:17, citing Ps 110:4). Christ is the one throne on which royal and priestly authority permanently coexist without conflict — the &#x201C;counsel of peace&#x221D; (<em>atsat shalom</em>) between the offices is the shalom Christ himself embodies and proclaims (John 14:27).</p>',
        "14": '<p class="christ-theme">The crown is to be kept in the temple as a memorial to the donors from Babylon. The crowns placed in the temple function as a promise — a material reminder of the coronation oracle given through the symbolic action. Revelation 4:10 describes the twenty-four elders casting their crowns before the throne. The crowns held in trust in Zechariah\'s temple become the crowns that the elders lay before the one who sits on the throne — from covenant memorial to eschatological worship. The keeping of the crown until its fulfillment is the posture of faith that waits for what has been promised.</p>',
        "15": '<p class="christ-direct">&#x201C;And those who are far off shall come and help to build the temple of YHWH. And you shall know that YHWH of Hosts has sent me to you. And this shall come to pass, if you will diligently obey the voice of YHWH your God.&#x221D; The universalism of the temple-building — &#x201C;those who are far off&#x221D; (<em>rechoqim</em>) coming to build — is Paul\'s language for Gentile inclusion: &#x201C;But now in Christ Jesus you who once were far off have been brought near by the blood of Christ&#x221D; (Eph 2:13). The far ones who come to build the temple of Zechariah are the far ones who are brought near by the cross to become &#x201C;a holy temple in the Lord&#x221D; (Eph 2:21).</p>',
    },
    "7": {
        "1": '<p class="christ-theme">A new oracle dated to the fourth year of Darius — two years after the visions, when the temple is under construction. The precise dating marks this as a new unit of instruction distinct from the vision sequence. The historicization of prophetic word — embedded in dateable moments — is the character of biblical prophecy: YHWH speaks into specific human situations, not in timeless generalities. This is the pattern Christ embodies: born &#x201C;when the fullness of time had come&#x221D; (Gal 4:4), crucified under Pontius Pilate, raised on the third day — divine action dated and embedded in human history.</p>',
        "2": '<p class="christ-theme">Delegates from Bethel come to seek the Lord and ask the priests whether the fasting of the fifth month should continue. The question is practical and pastoral — the fasting had marked the anniversary of the temple\'s destruction; now that the temple is being rebuilt, is the fast still appropriate? The concern is whether religious practice tracks the new reality being created by divine action. Christ addresses the same question about fasting practice: &#x201C;Can the wedding guests fast while the bridegroom is with them? As long as they have the bridegroom with them, they cannot fast&#x221D; (Mark 2:19). The new reality changes the appropriate practice.</p>',
        "3": '<p class="christ-theme">The question posed to the priests: &#x201C;Should I mourn and practice abstinence in the fifth month, as I have done for so many years?&#x221D; The accumulated years of fasting — &#x201C;so many years&#x221D; — represent habitual religious practice that may or may not still be connecting to the original intention. Jesus diagnoses the same disconnection in the Pharisees: they fast twice a week (Luke 18:12), but the practice has become self-validating rather than God-directed. He calls for &#x201C;sincere&#x221D; fasting done for the Father, not for show (Matt 6:17-18). The question from Bethel is whether practice still serves its purpose.</p>',
        "4": '<p class="christ-theme">YHWH\'s response comes to Zechariah rather than the priests — bypassing the expected channels. The divine word comes where YHWH chooses, not where institutional structure requires it. This is the pattern of Jesus\'s ministry: he speaks with authority &#x201C;and not as the scribes&#x221D; (Matt 7:29), bypassing the authoritative commentary tradition to address the word directly. The one who has authority to speak YHWH\'s word does not need institutional validation; the word\'s authority is self-authenticating.</p>',
        "5": '<p class="christ-theme">&#x201C;Say to all the people of the land and to the priests, \'When you fasted and mourned in the fifth month and in the seventh, for these seventy years, was it for me that you fasted?&#x221D; The question penetrates to motivation: was the fasting for YHWH or for the self? The seventy years of fasting may have been more about communal grief than covenant orientation toward YHWH. Jesus asks the same question about every religious practice: &#x201C;Beware of practicing your righteousness before other people in order to be seen by them&#x221D; (Matt 6:1). The test is always whether the practice is genuinely Godward or self-serving.</p>',
        "6": '<p class="christ-theme">&#x201C;And when you eat and when you drink, do you not eat for yourselves and drink for yourselves?&#x221D; Even the non-fasting times — eating and drinking — may be self-directed rather than covenantally oriented. Paul faces the same question about eating and drinking in 1 Corinthians 10:31: &#x201C;Whether you eat or drink, or whatever you do, do all to the glory of God.&#x221D; The sanctification of ordinary eating and drinking — turning self-directed appetite into covenantal worship — is the call of both Zechariah 7:6 and Pauline ethics. Christ makes this possible: the one who instituted the Lord\'s Supper transforms eating and drinking into participation in his own death and resurrection.</p>',
        "7": '<p class="christ-theme">The previous prophets had called for the same thing: justice and mercy. &#x201C;Were not these the words that YHWH proclaimed by the former prophets, when Jerusalem was inhabited?&#x221D; The ethical demand is not novel — it has been the consistent prophetic call throughout Israel\'s history. Christ does not innovate but fulfills: &#x201C;Do not think that I have come to abolish the Law or the Prophets; I have not come to abolish them but to fulfill them&#x221D; (Matt 5:17). The call to justice and mercy that the former prophets issued is the same call Christ intensifies in the Sermon on the Mount — not replacing but deepening.</p>',
        "8": '<p class="christ-theme">The word of YHWH comes to Zechariah — another direct oracle. The repeated formula &#x201C;the word of YHWH came to me&#x221D; marks each unit of the book as individually authorized. The plurality of specific divine words rather than one general message is the character of prophetic revelation: YHWH speaks in context-specific ways to specific situations. Christ is identified as the one Word (<em>Logos</em>) who gathers all specific prophetic words into himself: &#x201C;Long ago, at many times and in many ways, God spoke to our fathers by the prophets, but in these last days he has spoken to us by his Son&#x221D; (Heb 1:1-2).</p>',
        "9": '<p class="christ-direct">&#x201C;Thus says YHWH of Hosts: Render true judgments, show kindness and mercy to one another.&#x221D; Three commands: <em>mishpat emet</em> (true/just judgments), <em>chesed ve-rachamim</em> (kindness and compassion). These are the three virtues Jesus identifies as &#x201C;the weightier matters of the law&#x221D; in Matthew 23:23 — &#x201C;justice and mercy and faithfulness.&#x221D; The Pharisees tithed meticulously but neglected these. Jesus does not abolish tithing — &#x201C;you should have done&#x221D; them too — but insists that the ethical demands of the covenant are not superseded by ritual precision. The <em>chesed ve-rachamim</em> of Zechariah 7:9 is the heart of what Christ fulfills and commends.</p>',
        "10": '<p class="christ-direct">&#x201C;Do not oppress the widow, the fatherless, the sojourner, or the poor, and let none of you devise evil against another in your heart.&#x221D; The four vulnerable categories — widow, orphan, sojourner, poor — are the standard covenant concern throughout the Torah and prophets. Jesus concentrates all four in his beatitudes: &#x201C;Blessed are the poor in spirit&#x221D;; his ministry is announced as &#x201C;good news to the poor&#x221D; (Luke 4:18, citing Isa 61:1). The protection of the vulnerable is not peripheral but central to what the covenant means — and Christ embodies this in his ministry of healing the marginalized and welcoming the outsider.</p>',
        "11": '<p class="christ-theme">&#x201C;But they refused to pay attention and turned a stubborn shoulder and stopped their ears so that they could not hear.&#x221D; The physical metaphors for covenant refusal — stubborn shoulder (resisting the yoke), stopped ears — describe a community actively hardening itself against the divine call. Jesus diagnoses the same condition in Jerusalem: &#x201C;How often would I have gathered your children together as a hen gathers her brood under her wings, and you were not willing!&#x221D; (Matt 23:37). The hardening that Zechariah describes as historical past is the hardening Jesus weeps over as present reality — and the hardening that Paul describes as partial and purposeful in Romans 11:25.</p>',
        "12": '<p class="christ-theme">&#x201C;They made their hearts as hard as flint and would not listen to the law or to the words that YHWH of Hosts had sent by his Spirit through the earlier prophets.&#x221D; <em>Shamir</em> (flint) — the hardest stone known in the ancient world, used for cutting tools. The heart as flint is impenetrable to the divine word. Hebrews 3:7-8 cites Psalm 95:7-8 in exactly this context: &#x201C;Today, if you hear his voice, do not harden your hearts.&#x221D; The warning against flint-hearts is perpetually relevant — and Christ is the one through whom the heart of stone can be replaced by a heart of flesh (Ezek 36:26). The new covenant promise is precisely what the flint-hearted ancestors refused.</p>',
        "13": '<p class="christ-theme">&#x201C;Therefore, as I called and they did not listen, so they called and I did not listen, says YHWH of Hosts.&#x221D; The principle of reciprocal non-hearing — they did not hear YHWH, so YHWH did not hear them — is the covenant consequence of persistent refusal. But the NT announces a reversal of this: Christ cries out &#x201C;My God, my God, why have you forsaken me?&#x221D; (Matt 27:46) and enters the condition of divine non-hearing on behalf of those who deserved it — so that those who were formerly not heard might now be heard through his intercession (Heb 7:25; 1 John 2:1-2).</p>',
        "14": '<p class="christ-theme">&#x201C;And I scattered them with a whirlwind among all the nations that they had not known. The land was left desolate behind them, so that no one went to and fro.&#x221D; The scattering-among-the-nations is the covenantal consequence enacted — and it is also the mechanism of the gospel\'s spread. In Acts 8:1-4, the persecution that scatters the Jerusalem church &#x201C;went about preaching the word.&#x221D; What Zechariah describes as judgment (the whirlwind-scatter) becomes in the NT the means of gospel propagation. YHWH\'s redemptive sovereignty turns the judgment-scatter into the mission-scatter — the gathered community of every nation is assembled from the dispersed.</p>',
    }
}

def main():
    existing = load_comm('mkt-christ', 'zechariah')
    merge_comm(existing, ZECHARIAH)
    save_comm('mkt-christ', 'zechariah', existing)
    print('Zechariah 1-7 mkt-christ written.')

if __name__ == '__main__':
    main()
